        (*val) += 32;

    if (x & (1ull << 3))
        (*val) += 64;
    else
        (*val) += 128;

    if (x & (1ull << 4))
        (*val) += 256;
    else
        (*val) += 512;

    if (x & (1ull << 5))
        (*val) += 1024;
    else
        (*val) += 2048;

    if (x & (1ull << 6))
        (*val) += 4096;
    else
        (*val) += 8192;

    if (x & (1ull << 7))
        (*val) += 16384;
    else
        (*val) += 32768;

    if (x & (1ull << 8))
        (*val) += 65536;
    else
        (*val) += 131072;

    if (x & (1ull << 9))
        (*val) += 262144;
    else
        (*val) += 524288;

    return 1;
}

